#include <bits/stdc++.h>
using namespace std;
long long n,m,a[1003][1003],up[1003],down[1003],dp[1003];
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++)cin>>a[i][j];
    dp[1]=a[1][1];
    for(int i=2;i<=n;i++)dp[i]=dp[i-1]+a[i][1];
    for(int j=2;j<=m;j++){
        for(int i=1;i<=n;i++)down[i]=(i==1? dp[i]:max(dp[i],down[i-1]))+a[i][j];
        for(int i=n;i;i--)up[i]=(i==n? dp[i]:max(dp[i],up[i+1]))+a[i][j];
        for(int i=1;i<=n;i++)dp[i]=max(up[i],down[i]);
    }
    cout<<dp[n];
    return 0;
}
